INSERT INTO
  `SystemPolicy` (
    `id`,
    `type`,
    `content`,
    `version`,
    `isActive`,
    `createdAt`,
    `updatedAt`
  )
VALUES
  (
    'c7f8212e-c669-4ff2-a5c2-866f23909ccd',
    'ABOUT_US',
    'About Us\nBe-Vision delivers a modern Human Resource Management System (HRMS) for businesses that need end-to-end employee lifecycle management. Our platform streamlines:\n\nemployee onboarding and profile management\nattendance, leave, and correction tracking\ncompany dashboard and subscription administration\nsecure authentication and role-based access\nnotification delivery for approvals, reminders, and updates\nadvanced features like face recognition and document uploads\nOur mission is to empower HR teams and business leaders with secure, compliant, and automated workforce management tools that reduce manual effort and improve operational visibility.',
    '1.0.1',
    1,
    '2026-07-08 09:19:25.856',
    '2026-07-08 11:32:07.539'
  );
INSERT INTO
  `SystemPolicy` (
    `id`,
    `type`,
    `content`,
    `version`,
    `isActive`,
    `createdAt`,
    `updatedAt`
  )
VALUES
  (
    'e7aad597-e89a-4915-9747-af887cd4e846',
    'PRIVACY_POLICY',
    'Privacy Policy\n1. Information We Collect\nWe collect information needed to operate the HRMS and provide support:\n\nbusiness and company details\nuser and employee profiles\nattendance records\nleave and correction requests\nuploaded documents and images\nauthentication data\nusage logs and notification history\n2. How We Use Data\nData is used to:\n\ndeliver HRMS functionality\nauthenticate users and secure access\nmanage subscriptions and billing\nsend notifications, reminders, and alerts\nimprove our service and platform reliability\n3. Data Sharing\nWe do not sell user data. We may share data with:\n\nservice providers who support operations\nlegal authorities when required by law\naffiliates as permitted under the agreement\n4. Security\nWe use encryption and access controls to protect data. Regular monitoring and security updates help prevent unauthorized access.\n\n5. Employee Privacy\nEmployee information is handled with confidentiality. Only authorized personnel and designated company administrators may access employee-specific records.\n\n6. Cookies and Tracking\nIf the service uses web components, session and analytics cookies may be used to improve experience and diagnose issues.\n\n7. Data Retention\nWe retain data as needed to provide the service and comply with legal obligations. When accounts are closed, data may be archived or deleted according to policy.\n\n8. User Rights\nUsers may request access to their information, correct inaccuracies, or delete data subject to applicable laws and contractual obligations.\n\n9. Contact\nFor privacy questions or data requests, contact our support team at [support@example.com] or through the designated support channel',
    '1.0.1',
    1,
    '2026-07-08 09:06:35.594',
    '2026-07-08 11:23:54.641'
  );
INSERT INTO
  `SystemPolicy` (
    `id`,
    `type`,
    `content`,
    `version`,
    `isActive`,
    `createdAt`,
    `updatedAt`
  )
VALUES
  (
    'f48c836d-8142-4342-91eb-410429e48814',
    'TERMS_AND_CONDITIONS',
    'Terms and Conditions\n1. Acceptance of Terms\nBy using our HRMS platform, you agree to these Terms and Conditions. Use of the service constitutes acceptance of the policies described here.\n\n2. Service Scope\nThe platform provides HR management features including:\n\nattendance tracking\nleave management\nemployee onboarding\nnotifications\ncompany-level administration\nsubscription-based access\n3. User Accounts\nUsers must provide accurate information during account creation. You are responsible for all activity under your account and must keep credentials secure.\n\n4. Access and Use\nAccess is granted to authorized administrators, HR staff, and employees. Unauthorized access or misuse of the system is prohibited.\n\n5. Subscription and Billing\nSubscription fees apply for paid plans. See your agreement for billing cycles, renewal terms, and cancellation policies.\n\n6. Data and Content\nUsers retain ownership of their HR data. We store and process data to provide the service, including employee records, attendance logs, leave requests, and uploaded documents.\n\n7. Intellectual Property\nThe software, user interface, and related content are the intellectual property of [Company Name]. Users may not copy, modify, or redistribute the platform without permission.\n\n8. Privacy and Security\nWe implement industry-standard security practices to protect user data. Privacy is governed by our Privacy Policy.\n\n9. Limitations of Liability\nWe are not liable for indirect, incidental, or consequential damages arising from platform use. Liability for direct damages is limited to the fees paid for the service over the prior 12 months.\n\n10. Termination\nWe may suspend or terminate access for violations of these terms or misuse of the platform. Users may also cancel their subscription according to the agreed terms.\n\n11. Changes to Terms\nWe may update these Terms and Conditions at any time. Continued use of the service after changes constitutes acceptance.',
    '1.0.1',
    1,
    '2026-07-08 09:06:20.487',
    '2026-07-08 11:23:15.361'
  );

